const { ApolloServer } = require('@apollo/server');
const { startStandaloneServer } = require('@apollo/server/standalone');

const typeDefs = `#graphql
  type Invoice {
    id: ID!
    number: String
    status: String
    currency: String
    total: Float
    subtotal: Float
    tax: Float
    issuedAt: String
    dueAt: String
    customerName: String
    customerEmail: String
    notes: String
    createdAt: String
    updatedAt: String
  }

  type Query {
    invoice(id: ID!): Invoice
  }
`;

function createInvoiceResolver({ invoiceStore }) {
  return async (_, { id }, context) => {
    if (!context?.user) throw new Error('UNAUTHENTICATED');
    if (!id) throw new Error('BAD_USER_INPUT');

    const invoice = await invoiceStore.getById(String(id));
    return invoice || null;
  };
}

function createServer({ invoiceStore }) {
  const resolvers = {
    Query: {
      invoice: createInvoiceResolver({ invoiceStore }),
    },
  };

  return new ApolloServer({ typeDefs, resolvers });
}

